package unverified;

import metadata.BehavioralDifference;
import metadata.DifferenceType;

import org.junit.jupiter.api.Test;

import static unverified.ClonePairAliasAwareInvocationTestSupport.*;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

class ClonePair6106DifferenceFindingTest {

    private final ClonePair6106 subject = new ClonePair6106();

    /**
     * Generated by Codex (GPT-5).
     * Difference type: return_value.
     * Difference manifestation: the methods return different values.
     * separating case: distinct_equal_0_1 ["leftValue", "rightValue"]
     */
    @Test
    @BehavioralDifference(DifferenceType.RETURN_VALUE)
    void methodsDisagreeOnGeneratedInput() {
        InvocationOutcome method1Outcome = captureWithTimeout(values -> subject.method1((Object[]) values[0], (Object[]) values[1]), 1000L, buildMethod1Inputs());
        InvocationOutcome method2Outcome = captureWithTimeout(values -> subject.method2((Object[]) values[0], (Object[]) values[1]), 1000L, buildMethod2Inputs());

        assertCoreOutcome(
            method1Outcome,
            "OK",
            "Boolean(true)",
            null,
            "java.lang.Object[][java.lang.Object[][String(YWxpYXM=)],java.lang.Object[][String(YWxpYXM=)]]",
            "java.lang.Object[][java.lang.Object[][String(YWxpYXM=)],java.lang.Object[][String(YWxpYXM=)]]"
        );
        assertCoreOutcome(
            method2Outcome,
            "OK",
            "Boolean(false)",
            null,
            "java.lang.Object[][java.lang.Object[][String(YWxpYXM=)],java.lang.Object[][String(YWxpYXM=)]]",
            "java.lang.Object[][java.lang.Object[][String(YWxpYXM=)],java.lang.Object[][String(YWxpYXM=)]]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
    }

    private Object[] buildMethod1Inputs() {
        Object[] leftValue = new Object[]{new String("alias")};
        Object[] rightValue = new Object[]{new String("alias")};
        return new Object[]{leftValue, rightValue};
    }

    private Object[] buildMethod2Inputs() {
        Object[] leftValue = new Object[]{new String("alias")};
        Object[] rightValue = new Object[]{new String("alias")};
        return new Object[]{leftValue, rightValue};
    }

}
